  const char = str[index];
  if (char === '\r') {
    if (str[index + 1] === '\n') {
      return { matched: true, length: 2 };
    }
    return { matched: true, length: 1 };
  }

  if (char === '\n') {
    return { matched: true, length: 1 };
  }

  return { matched: false, length: 0 };
}

