  rows: Record<string, unknown>[],
  headers: string[],
  errors: CSVError[],
): CSVResult {
  const result: CSVResult = {
    rows,
    headers,
    errors,
    filter(predicate) {
      return createCSVResult(rows.filter(predicate), headers, errors);
    },
    sum(column) {
      return rows.reduce((acc, row) => {
        const value = row[column];
        if (typeof value === 'number' && !Number.isNaN(value)) {
          return acc + value;
        }
        return acc;
      }, 0);
    },
    average(column) {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const value = row[column];
        if (typeof value === 'number' && !Number.isNaN(value)) {
          total += value;
          count += 1;
        }
      }
      return count === 0 ? 0 : total / count;
