  const quote = options.quote ?? DEFAULT_QUOTE;
  const lineSeparator = options.lineSeparator;

  const rows: { values: string[]; rowNumber: number }[] = [];
  let field: string = '';
  let currentRow: string[] = [];
  let inQuotes = false;
  let rowNumber = 1;

  const pushField = () => {
    currentRow.push(field);
    field = '';
  };

  const pushRow = () => {
    // Always push the row even if empty so headers can be detected on empty input.
    rows.push({ values: currentRow.slice(), rowNumber });
    currentRow = [];
    rowNumber += 1;
