cat <<'EOF' > csv-parser.test.ts
import { parseCSV } from './csv-parser';

function assert(condition: boolean, message?: string) {
  if (!condition) {
    throw new Error(message ?? 'Assertion failed');
  }
}

function expectDeepEqual(actual: unknown, expected: unknown, message?: string) {
  const actualJson = JSON.stringify(actual);
  const expectedJson = JSON.stringify(expected);
  if (actualJson !== expectedJson) {
    throw new Error(message ?? `Expected ${expectedJson} but got ${actualJson}`);
  }
}

function runTests() {
  // Basic parsing
  const basicCsv = 'name,age\nAlice,30\nBob,25';
  const basic = parseCSV(basicCsv);
  expectDeepEqual(basic.headers, ['name', 'age']);
  assert(basic.errors.length === 0, 'Basic parsing should not expose errors');
  assert(basic.rows.length === 2, 'Should parse two data rows');
  assert(basic.rows[0].name === 'Alice');
  assert(basic.rows[0].age === 30);
  assert(basic.rows[1].name === 'Bob');
  assert(basic.rows[1].age === 25);

  // Quoted fields with commas
  const quoted = parseCSV('name,notes\n"Smith, John","Hello, world, and beyond"');
  assert(quoted.rows[0].name === 'Smith, John');
  assert(quoted.rows[0].notes === 'Hello, world, and beyond');

  // Escaped quotes
  const escaped = parseCSV('quote\n"She said ""Hello"""');
  assert(escaped.rows[0].quote === 'She said "Hello"');

  // Custom delimiters, quotes, and line separators
  const custom = parseCSV("id|value||1|'A|B'||2|'C|D'", {
    delimiter: '|',
    quote: "'",
    lineSeparator: '||',
  });
  expectDeepEqual(custom.headers, ['id', 'value']);
  assert(custom.rows.length === 2);
  assert(custom.rows[0].value === 'A|B');
  assert(custom.rows[1].value === 'C|D');

  // Type coercion for numbers, booleans, nulls, and strings
  const typeCsv = 'value\n1\n2.5\nTRUE\nfalse\nnull\nNULL\n""\nfoo\nbar';
  const typed = parseCSV(typeCsv);
  expectDeepEqual(typed.rows.map((row) => row.value), [
    1,
    2.5,
    true,
    false,
    null,
    null,
    null,
    'foo',
    'bar',
  ]);

  // Malformed row detection
  const malformed = parseCSV('id,name\n1,Alice\n2');
  assert(malformed.errors.length === 1, 'Malformed row should be captured');
  assert(malformed.errors[0].row === 3, 'Malformed row should report correct row number');

  // Filter functionality
  const filterCsv = parseCSV('name,status\nAlice,active\nBob,inactive\nCara,active');
  const activeOnly = filterCsv.filter((row) => row.status === 'active');
  expectDeepEqual(activeOnly.rows.map((row) => row.name), ['Alice', 'Cara']);

  // Aggregation helpers
  const aggregateCsv = parseCSV('category,amount\nfood,10\ntravel,20\nfood,5');
  assert(aggregateCsv.sum('amount') === 35);
  assert(aggregateCsv.average('amount') === 35 / 3);
  assert(aggregateCsv.count() === 3);
  const grouped = aggregateCsv.groupBy('category');
  assert(grouped.get('food')?.length === 2);
  assert(grouped.get('travel')?.length === 1);

  // Edge cases: empty input
  const empty = parseCSV('');
  assert(empty.headers.length === 0);
  assert(empty.rows.length === 0);
  assert(empty.errors.length === 0);

  // Single column
  const singleColumn = parseCSV('letter\na');
  expectDeepEqual(singleColumn.headers, ['letter']);
  assert(singleColumn.rows.length === 1);
  assert(singleColumn.rows[0].letter === 'a');

  // Single row (header only)
  const headerOnly = parseCSV('single');
  assert(headerOnly.count() === 0, 'Header-only input should yield zero rows');
  expectDeepEqual(headerOnly.headers, ['single']);

  // Very large fields
  const largeText = 'text\n"' + 'x'.repeat(5000) + '"';
  const large = parseCSV(largeText);
  assert(large.rows[0].text === 'x'.repeat(5000));

  console.log('All csv-parser tests passed');
}

runTests();
