    return createCSVResult([], [], []);
  }

  const rows: { values: string[]; rowNumber: number }[] = [];
  let field: string = '';
  let currentRow: string[] = [];
  let inQuotes = false;
  let rowNumber = 1;
  let hasPendingField = false;

  const pushField = () => {
    currentRow.push(field);
    field = '';
    hasPendingField = false;
  };

  const pushRow = () => {
    rows.push({ values: currentRow.slice(), rowNumber });
    currentRow = [];
    rowNumber += 1;
    hasPendingField = false;
  };

  const matchLineBreak = (idx: number) => {
    if (lineSeparator) {
      if (input.startsWith(lineSeparator, idx)) {
        return { matched: true, length: lineSeparator.length };
      }
      return { matched: false, length: 0 };
    }
    return defaultLineBreak(input, idx);
  };

  for (let i = 0; i < input.length; i += 1) {
    const char = input[i];

    if (inQuotes) {
      if (char === quote) {
        const nextChar = input[i + 1];
        if (nextChar === quote) {
          field += quote;
          i += 1;
          hasPendingField = true;
          continue;
        }
        inQuotes = false;
        continue;
      }

      field += char;
      hasPendingField = true;
      continue;
    }

    if (char === quote) {
      inQuotes = true;
      hasPendingField = true;
      continue;
    }

    if (char === delimiter) {
      pushField();
      continue;
    }

    const lineBreak = matchLineBreak(i);
    if (lineBreak.matched) {
      pushField();
      pushRow();
      i += lineBreak.length - 1;
      continue;
    }

    field += char;
    hasPendingField = true;
  }

  if (hasPendingField || currentRow.length > 0) {
    if (hasPendingField) {
      pushField();
    }
    if (currentRow.length > 0) {
      pushRow();
    }
  }

  if (rows.length === 0) {
    return createCSVResult([], [], []);
  }

  const headerRow = rows[0];
  const headers = headerRow.values.map((header) => header.trim());
  const dataRows = rows.slice(1);
  const parsedRows: Record<string, unknown>[] = [];
  const errors: CSVError[] = [];

  for (const dataRow of dataRows) {
    if (dataRow.values.length !== headers.length) {
      errors.push({
        row: dataRow.rowNumber,
        message: `Row length ${dataRow.values.length} does not match headers length ${headers.length}`,
      });
      continue;
    }

    const rowObject: Record<string, unknown> = {};
    for (let colIndex = 0; colIndex < headers.length; colIndex += 1) {
      const header = headers[colIndex];
      const rawValue = dataRow.values[colIndex];
      rowObject[header] = coerceValue(rawValue);
    }
    parsedRows.push(rowObject);
  }

  return createCSVResult(parsedRows, headers, errors);
}
